REPLACE INTO app_product (id, name, price, sale_price, digital, image, description, material, size, origin, quality) VALUES (1, 'bàn ăn gỗ cao su moho oslo 901', 4490000.0, 3990000.0, 0, 'main/ban-an-go-cao-su-moho-oslo-901_1.jpg', 'bàn ăn gỗ cao su moho oslo 901 nổi bật với kiểu dáng tối giản nhưng vẫn đảm bảo công năng sử dụng. chất liệu gỗ công nghiệp (mdf/mfc) giúp sản phẩm chống cong vênh và dễ vệ sinh. kích thước dài 1m4 x rộng 75cm x cao 73cm, phù hợp với nhiều không gian. mang lại không gian ấm cúng cho bữa ăn gia đình. tạo điểm nhấn sang trọng cho phòng ăn.', 'gỗ công nghiệp (mdf/mfc)', 'dài 1m4 x rộng 75cm x cao 73cm ', 'Việt Nam', 'Loại 1');
