REPLACE INTO app_product (id, name, price, sale_price, digital, image, description, material, size, origin, quality) VALUES (2, 'bàn ăn gỗ cao su tự nhiên hobro 301 (màu nâu)', 5890000.0, 4490000.0, 0, 'main/ban-an-go-cao-su-tu-nhien-hobro-301-mau-nau_1.jpg', 'bàn ăn gỗ cao su tự nhiên hobro 301 (màu nâu) mang phong cách hiện đại, phù hợp với không gian sống ngày nay. sản phẩm sử dụng chất liệu gỗ công nghiệp (mdf/mfc), đảm bảo độ bền và tính thẩm mỹ cao. kích thước rộng 800 x dài 1400/ 1600 x cao 752, phù hợp với nhiều không gian. phù hợp cho gia đình 4–6 người. tạo điểm nhấn sang trọng cho phòng ăn.', 'gỗ công nghiệp (mdf/mfc)', 'rộng 800 x dài 1400/ 1600 x cao 752', 'Việt Nam', 'Loại 1');
